# Purple Rainmaker — Example Configuration
# Copy this to config.py and fill in your values.
# config.py is gitignored and never shared.
#
# This file is generated automatically on first run via the setup page.
# You can also edit it manually and restart the app.

AUTH_USERNAME = 'your_username'
AUTH_PASSWORD = 'your_password'
REPORTS_DIR   = '/path/to/your/reports'
BIND_HOST     = '127.0.0.1'   # Default: localhost only. Change to '0.0.0.0' for LAN access.
